```plantuml
@startuml

title Modulo-matrícula/Informática

class Matrícula {
  -id: Int
  -cliente: Client
  -tempo: Int
  -quadra: Turma
  +registraMatrícula(): Int
}

class Aluno {
  -id: Int
  -nome: String
  -locaçao: List<Matrícula>
}

interface ControleNúmeroMatrícula <<interface>> {
  #quantidadeDeMatrícula: Int
  +registraMatrícula(): Int
}

class Turma {
  -numero: Int
  -aluguel: Matrícula
  -ginasio: Curso
  +getcontroleNúmeroMatrícula()
}

class Curso {
  -nome: String
  -profesor: String
  -quadra: List<Turma>
}

Aluno *-left- "0..*" Matrícula : composição
Matrícula ..|> ControleNúmeroMatrícula : realização
Turma "1" *-left- "1..*" Matrícula : composição >
Turma ..> ControleNúmeroMatrícula : dependência
Curso "1" *-right- "1..*" Turma : composição

@enduml
```
